Voici un petit script perl qui utilise les bibliothèques necessaires pour extraire des informations à partir d'un PDF. On va utiliser `PDF::API2` pour lire le PDF et `Text::CSV` pour gérer les données extraites, si c'est une table de données que tu veux récupérer.

```perl
use strict;
use warnings;
use PDF::API2;
use Text::CSV;

# Chemin vers le fichier PDF
my $pdf_file = 'mon_fichier.pdf';

# Ouverture du PDF
my $pdf = PDF::API2->open($pdf_file);

# Récupération des informations du document
my $info = $pdf->info;
print "Auteur: " . $info->{'/Author'} . "\n";
print "Date: " . $info->{'/ModDate'} . "\n";

# Extraction des données de la table si nécessaire
my $page = $pdf->page(1);  # On commence par la première page
my $content = $page->mediabox->width . "x" . $page->mediabox->height;

# On supposera ici que le contenu de la table est séparé par des guillemets
my $csv = Text::CSV->new({ binary => 1, eol => $pdf->eol, auto_diag => 1 });
my @lines = $page->text;

foreach my $line (@lines) {
    next unless $line =~ /"(.*)"/;  # On filtre les lignes qui contiennent des guillemets
    my @data = $csv->getline_array($line);
    print join(", ", @data), "\n";
}

